}

/* ===== 🎯 横屏模式优化 ===== */
@media screen and (max-width: 767px) and (orientation: landscape) {
  :root {
    --topbar-height: 26px;
    --base-margin: 4px;
    --content-padding: 8px;
  }

  #top-settings-holder {
    top: 2px !important;
  }

  .drawer-toggle.drawer-header {
    height: calc(var(--topbar-height) - 2px) !important;
    font-size: 11px !important;
  }

  #chat .ch_name {
    padding: 6px 12px !important;
    margin: 4px 0 8px 0 !important;
  }

  .menu_button {
    min-height: 36px !important;
    padding: 4px 8px !important;
  }

  #send_textarea, #sendbut_textarea, textarea#send_textarea {
    min-height: 36px !important;
    height: 36px !important;
    padding: 8px 12px !important;
  }
}

/* ===== 🎯 触控设备优化 ===== */
@media (hover: none) and (pointer: coarse) {
  /* 触控设备特殊优化 */
  .menu_button, button, select, input, textarea {
    min-height: 44px !important;
    touch-action: manipulation !important;
  }

  .drawer-toggle.drawer-header {
    min-height: 40px !important;
    touch-action: manipulation !important;
  }

  /* 禁用hover效果在触控设备上 */
  .menu_button:hover::before,
  #nonQRFormItems:hover,
  .drawer-toggle.drawer-header:hover::before {
    opacity: 0 !important;
    transform: none !important;
  }
}

/* ===== 🎯 高DPI屏幕优化 ===== */
@media (-webkit-min-device-pixel-ratio: 2), (min-resolution: 192dpi) {
  /* 高DPI屏幕特殊优化 */
  .drawer-icon, .fa, .fas, .far {
    -webkit-font-smoothing: antialiased !important;
    -moz-osx-font-smoothing: grayscale !important;
  }

  #top-settings-holder {
    backdrop-filter: blur(15px) saturate(1.3) !important;
    -webkit-backdrop-filter: blur(15px) saturate(1.3) !important;
  }

  .drawer-content {
    backdrop-filter: blur(15px) saturate(1.2) !important;
    -webkit-backdrop-filter: blur(15px) saturate(1.2) !important;
  }
}

/* ===== 🎯 无障碍优化 ===== */
@media (prefers-reduced-motion: reduce) {
  /* 动画敏感用户优化 */
  *, *::before, *::after {
    animation-duration: 0.01ms !important;
    animation-iteration-count: 1 !important;
    transition-duration: 0.01ms !important;
    scroll-behavior: auto !important;
  }

  .drawer-content, #top-settings-holder {
    animation: none !important;
    transition: none !important;
  }
}

@media (prefers-contrast: high) {
  /* 高对比度优化 */
  :root {
    --border-jade: rgba(130, 233, 222, 0.8) !important;
    --border-rouge: rgba(249, 164, 200, 0.8) !important;
  }

  .menu_button, select, input, textarea {
    border-width: 2px !important;
  }
}

/* --- 性能优化 --- */
#top-settings-holder, .drawer-content, #chat, .mes,
select, button, .menu_button, input, textarea {
  transform: translateZ(0);
  will-change: transform;
  backface-visibility: hidden;
  -webkit-backface-visibility: hidden;
}

/* 减少重绘优化 */
.mes_text p {
  contain: layout style;
  transform: translateZ(0);
}

.drawer-content:not(.closedDrawer) {
  contain: layout style;
}

.closedDrawer {
  contain: strict;
  content-visibility: hidden;
}

/* --- 最终确保兼容性 --- */
@supports not (backdrop-filter: blur(1px)) {
  .drawer-content, #chat {
    background: rgba(22, 28, 35, 0.98) !important;
  }

  #top-settings-holder {
    background: rgba(22, 28, 35, 0.98) !important;
  }
}

/* ===== 🎯 移动端特殊功能优化 ===== */

/* 防止移动端缩放 */
@media screen and (max-width: 767px) {
  html {
    -webkit-text-size-adjust: 100% !important;
    -ms-text-size-adjust: 100% !important;
    text-size-adjust: 100% !important;
  }

  /* 优化移动端选择 */
  ::selection {
    background: rgba(130, 233, 222, 0.3) !important;
    color: var(--text-main) !important;
  }

  ::-moz-selection {
    background: rgba(130, 233, 222, 0.3) !important;
    color: var(--text-main) !important;
  }

  /* 移动端输入框优化 */
  input, textarea, select {
    -webkit-appearance: none !important;
    -moz-appearance: none !important;
    appearance: none !important;
    border-radius: var(--box-radius) !important;
  }

  /* 移动端tap高亮移除 */
  * {
    -webkit-tap-highlight-color: transparent !important;
    -webkit-touch-callout: none !important;
  }
    /* 移动端滚动优化 */
  .drawer-content, #chat {
    -webkit-overflow-scrolling: touch !important;
  }
}

/* ===== 🎯 PWA和原生应用优化 ===== */
@media (display-mode: standalone) {
  /* PWA模式优化 */
  body {
    padding-top: calc(var(--topbar-height) + var(--base-margin) + env(safe-area-inset-top)) !important;
  }

  #top-settings-holder {
    top: calc(env(safe-area-inset-top) + 4px) !important;
  }
}

/* iOS Safari特殊优化 */
@supports (-webkit-appearance: none) {
  @media screen and (max-width: 767px) {
    /* 处理iOS Safari的viewport问题 */
    .drawer-content {
      height: calc(100vh - var(--topbar-height) - var(--base-margin) * 2 - env(safe-area-inset-bottom)) !important;
    }

    #chat {
      height: calc(100vh - var(--topbar-height) - var(--base-margin) * 3 - env(safe-area-inset-bottom)) !important;
    }
  }
}

/* ===== 🎯 性能优化增强 ===== */
@media screen and (max-width: 767px) {
  /* 移动端GPU加速 */
  #top-settings-holder, .drawer-content, #chat, .mes,
  .menu_button, #nonQRFormItems {
    transform: translateZ(0) !important;
    will-change: transform !important;
    backface-visibility: hidden !important;
    -webkit-backface-visibility: hidden !important;
  }

  /* 移动端内容可见性优化 */
  .drawer-content:not(.closedDrawer) {
    contain: layout style paint !important;
  }

  .closedDrawer {
    contain: strict !important;
    content-visibility: hidden !important;
  }

  /* 移动端字体渲染优化 */
  body, .mes_text p {
    text-rendering: optimizeSpeed !important;
    -webkit-font-smoothing: antialiased !important;
    -moz-osx-font-smoothing: grayscale !important;
  }
}

/* ===== 🎯 最终兼容性保障 ===== */
@supports not (backdrop-filter: blur(1px)) {
  /* 不支持backdrop-filter的设备回退方案 */
  @media screen and (max-width: 767px) {
    .drawer-content, #chat, #top-settings-holder, #nonQRFormItems {
      background: rgba(22, 28, 35, 0.98) !important;
    }
  }
}

@supports not (color-mix(in srgb, red, blue)) {
  /* 不支持color-mix的设备回退方案 */
  :root {
    --ui-color-sec: rgba(154, 168, 184, 0.5) !important;
  }
}

/* 打印样式优化 */
@media print {
  #top-settings-holder, .drawer-content {
    display: none !important;
  }

  #chat {
    position: static !important;
    margin: 0 !important;
    padding: 20px !important;
    background: white !important;
    color: black !important;
    box-shadow: none !important;
  }

  .mes_text p {
    background: transparent !important;
    color: black !important;
    text-shadow: none !important;
  }
}


